export function seedUnCybercrimeConvention(db) {
    console.log('  Seeding UN Cybercrime Convention...');
    const insertSource = db.prepare(`INSERT INTO sources (title, short_title, source_type, organization, adoption_date, entry_into_force_date, status, signatories_count, url, notes)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`);
    const insertArticle = db.prepare(`INSERT INTO articles (source_id, article_number, title, content, chapter, part, keywords)
     VALUES (?, ?, ?, ?, ?, ?, ?)`);
    const result = insertSource.run('United Nations Convention against Cybercrime', 'UN Cybercrime Convention', 'treaty', 'United Nations General Assembly', '2024-12-24', null, 'adopted', null, 'https://www.unodc.org/unodc/en/cybercrime/ad_hoc_committee/ahc_session10/main', 'First UN treaty on cybercrime. Adopted by UNGA after 3 years of negotiations. Open for signature from early 2025. Requires 40 ratifications for entry into force.');
    const srcId = Number(result.lastInsertRowid);
    const articles = [
        // Chapter I — General provisions
        { num: 'Article 1', title: 'Statement of purpose', content: 'The purpose of this Convention is to prevent and combat cybercrime more efficiently and effectively, to promote, facilitate and strengthen international cooperation with respect to cybercrime, and to strengthen measures for the prevention of and the fight against cybercrime, including through technical assistance and capacity-building, particularly for developing countries.', ch: 'Chapter I - General provisions', part: null, kw: 'purpose,international cooperation,capacity building' },
        { num: 'Article 2', title: 'Use of terms', content: 'For the purposes of this Convention: (a) "Information and communications technology system" means any device or group of interconnected or related devices, one or more of which, pursuant to a programme, performs automatic processing of data or any other function; (b) "Information and communications technology data" means any representation of facts, information or concepts in a form suitable for processing in an information and communications technology system, including a programme suitable to cause an information and communications technology system to perform a function; (c) "Electronic data" means data in electronic form.', ch: 'Chapter I - General provisions', part: null, kw: 'definitions,ICT system,ICT data,electronic data' },
        { num: 'Article 3', title: 'Scope of application', content: 'This Convention shall apply to the prevention, investigation and prosecution of criminal offences established in accordance with this Convention and to the collection, preservation, production and sharing of electronic evidence relating to any serious crime as defined in article 2 of this Convention.', ch: 'Chapter I - General provisions', part: null, kw: 'scope,serious crime,electronic evidence' },
        { num: 'Article 4', title: 'Protection of sovereignty', content: 'States Parties shall carry out their obligations under this Convention in a manner consistent with the principles of sovereign equality and territorial integrity of States and that of non-intervention in the domestic affairs of other States.', ch: 'Chapter I - General provisions', part: null, kw: 'sovereignty,territorial integrity,non-intervention' },
        { num: 'Article 5', title: 'Protection of human rights', content: 'States Parties shall ensure that the implementation of their obligations under this Convention is consistent with their obligations under international human rights law. Nothing in this Convention shall be interpreted as permitting the suppression of human rights or fundamental freedoms, including the right to privacy, freedom of expression, and freedom of opinion.', ch: 'Chapter I - General provisions', part: null, kw: 'human rights,privacy,freedom of expression,fundamental freedoms' },
        // Chapter II — Criminalization
        { num: 'Article 6', title: 'Illegal access', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the access to the whole or any part of an information and communications technology system.', ch: 'Chapter II - Criminalization', part: null, kw: 'illegal access,unauthorized access,hacking' },
        { num: 'Article 7', title: 'Illegal interception', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the interception, made by technical means, of non-public transmissions of information and communications technology data to, from or within an information and communications technology system, including electromagnetic emissions from an information and communications technology system carrying such data.', ch: 'Chapter II - Criminalization', part: null, kw: 'illegal interception,electromagnetic emissions,wiretapping' },
        { num: 'Article 8', title: 'Interference with ICT data', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the damaging, deletion, deterioration, alteration or suppression of information and communications technology data.', ch: 'Chapter II - Criminalization', part: null, kw: 'data interference,data destruction,data alteration' },
        { num: 'Article 9', title: 'Interference with ICT systems', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the serious hindering of the functioning of an information and communications technology system by inputting, transmitting, damaging, deleting, deteriorating, altering or suppressing information and communications technology data.', ch: 'Chapter II - Criminalization', part: null, kw: 'system interference,denial of service,DDoS' },
        { num: 'Article 10', title: 'Misuse of devices', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization: the production, procurement for use, sale, import, export, distribution or otherwise making available of a device or programme primarily designed or adapted for the purpose of committing offences established in articles 6 through 9; or a code, password, or similar data by which the whole or any part of an information and communications technology system is capable of being accessed, with intent that it be used for the purpose of committing offences established in articles 6 through 9.', ch: 'Chapter II - Criminalization', part: null, kw: 'misuse of devices,hacking tools,malware distribution' },
        { num: 'Article 11', title: 'Computer-related forgery', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the input, alteration, deletion or suppression of information and communications technology data, resulting in inauthentic data with the intent that it be considered or acted upon for legal purposes as if it were authentic.', ch: 'Chapter II - Criminalization', part: null, kw: 'computer forgery,data manipulation,inauthentic data' },
        { num: 'Article 12', title: 'Computer-related theft or fraud', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the causing of a loss of property to another person by: any input, alteration, deletion or suppression of information and communications technology data; or any interference with the functioning of an information and communications technology system, with intent to procure an economic benefit for oneself or for another person.', ch: 'Chapter II - Criminalization', part: null, kw: 'computer fraud,online fraud,theft,economic benefit' },
        { num: 'Article 13', title: 'Identity-related offences', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization: the acquisition, possession, use, transfer or offering for sale or distribution of the identification data of another natural or legal person, by means of an information and communications technology system, for the purpose of committing a criminal offence.', ch: 'Chapter II - Criminalization', part: null, kw: 'identity theft,identity fraud,identification data' },
        { num: 'Article 14', title: 'Child sexual abuse or exploitation material', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as criminal offences the production, offering, distribution, transmission, procurement, possession, and access to child sexual abuse or sexual exploitation material by means of an information and communications technology system. For the purposes of this article, "child sexual abuse material" means any material that visually depicts a child or a person appearing to be a child engaged in real or simulated sexually explicit conduct, or any visual depiction of the sexual parts of a child for primarily sexual purposes.', ch: 'Chapter II - Criminalization', part: null, kw: 'CSAM,child exploitation,child safety,online child abuse' },
        { num: 'Article 15', title: 'Solicitation or grooming of children', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally, the solicitation or grooming of a child, by means of an information and communications technology system, for the purpose of committing any offence established in accordance with article 14 of this Convention or engaging in sexual activity with that child.', ch: 'Chapter II - Criminalization', part: null, kw: 'grooming,solicitation,child protection,online grooming' },
        { num: 'Article 16', title: 'Non-consensual dissemination of intimate images', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence, when committed intentionally and without authorization, the distribution, dissemination, transmission, or making available to the public, by means of an information and communications technology system, of intimate images of another person, without the consent of the person depicted, causing or likely to cause serious harm.', ch: 'Chapter II - Criminalization', part: null, kw: 'intimate images,revenge pornography,non-consensual sharing,image-based abuse' },
        { num: 'Article 17', title: 'Money laundering', content: 'Each State Party shall adopt, in accordance with its domestic law, such legislative and other measures as may be necessary to establish as criminal offences money laundering involving proceeds derived from offences established in this Convention.', ch: 'Chapter II - Criminalization', part: null, kw: 'money laundering,proceeds of crime,financial crime' },
        { num: 'Article 18', title: 'Participation, attempt, and preparation', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish as criminal offences participation as an accomplice in, or organizing, directing, aiding, abetting, facilitating or counselling the commission of offences established in this Convention. Each State Party shall adopt such legislative and other measures as may be necessary to establish as a criminal offence an attempt to commit offences established in articles 6 through 12 and 17 of this Convention.', ch: 'Chapter II - Criminalization', part: null, kw: 'attempt,accomplice,aiding,abetting,participation' },
        { num: 'Article 19', title: 'Liability of legal persons', content: 'Each State Party shall adopt such measures as may be necessary, consistent with its legal principles, to establish the liability of legal persons for participation in the criminal offences established in this Convention.', ch: 'Chapter II - Criminalization', part: null, kw: 'corporate liability,legal persons,organizational liability' },
        { num: 'Article 20', title: 'Prosecution, adjudication, and sanctions', content: 'Each State Party shall make the commission of offences established in this Convention liable to sanctions that take into account the gravity of those offences. Each State Party shall ensure that the criminal offences established in this Convention are punishable by effective, proportionate and dissuasive sanctions.', ch: 'Chapter II - Criminalization', part: null, kw: 'sanctions,penalties,proportionate,dissuasive' },
        // Chapter III — Procedural measures and law enforcement
        { num: 'Article 21', title: 'Scope of procedural measures', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to establish the powers and procedures provided for in this chapter for the purpose of criminal investigations and proceedings related to the offences established in this Convention and for the collection of electronic evidence in relation to any serious crime.', ch: 'Chapter III - Procedural measures', part: null, kw: 'procedural measures,criminal investigation,electronic evidence' },
        { num: 'Article 22', title: 'Conditions and safeguards', content: 'Each State Party shall ensure that the establishment, implementation and application of the powers and procedures provided for in this chapter are subject to conditions and safeguards provided for under its domestic law, consistent with its obligations under international human rights law, which shall include the principle of proportionality. Such conditions and safeguards shall include judicial or other independent authorization or supervision, grounds justifying the application, and limitation of the scope and duration of such powers.', ch: 'Chapter III - Procedural measures', part: null, kw: 'safeguards,judicial oversight,proportionality,human rights' },
        { num: 'Article 23', title: 'Expedited preservation of stored electronic data', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to enable its competent authorities to order or otherwise obtain the expeditious preservation of specified electronic data, including traffic data, that has been stored by means of an information and communications technology system, in particular where there are grounds to believe that the data is vulnerable to loss or modification.', ch: 'Chapter III - Procedural measures', part: null, kw: 'data preservation,evidence preservation,expedited preservation' },
        { num: 'Article 24', title: 'Production orders', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to empower its competent authorities to order a person in its territory or a service provider offering services in that State to submit specified electronic data in that person\'s or service provider\'s possession or control, or subscriber information in the service provider\'s possession or control.', ch: 'Chapter III - Procedural measures', part: null, kw: 'production orders,data disclosure,subscriber information' },
        { num: 'Article 25', title: 'Search and seizure of stored electronic data', content: 'Each State Party shall adopt such legislative and other measures as may be necessary to empower its competent authorities to search or similarly access an information and communications technology system or part of it and electronic data stored therein, and to seize or similarly secure such electronic data.', ch: 'Chapter III - Procedural measures', part: null, kw: 'search and seizure,digital evidence,stored data' },
        { num: 'Article 26', title: 'Real-time collection of traffic data', content: 'Each State Party shall adopt such legislative and other measures as may be necessary, in relation to criminal offences established in this Convention and serious crime, to empower its competent authorities to collect or record through technical means, or to compel a service provider to collect or record or to cooperate and assist in the collection or recording of, traffic data in real time.', ch: 'Chapter III - Procedural measures', part: null, kw: 'real-time collection,traffic data,surveillance' },
        { num: 'Article 27', title: 'Interception of content data', content: 'Each State Party shall adopt such legislative and other measures as may be necessary, in relation to a range of serious criminal offences to be determined by its domestic law, to empower its competent authorities to collect or record through technical means, or to compel a service provider to collect or record or to cooperate and assist in the collection or recording of, content data in real time.', ch: 'Chapter III - Procedural measures', part: null, kw: 'content interception,lawful interception,content data' },
        { num: 'Article 28', title: 'Jurisdiction', content: 'Each State Party shall adopt such measures as may be necessary to establish its jurisdiction over the offences established in this Convention when the offence is committed: in its territory; on board a vessel flying its flag or an aircraft registered under its laws; or by one of its nationals or a habitual resident. Each State Party shall also take such measures as may be necessary to establish its jurisdiction when the offence is committed against one of its nationals, and when the alleged offender is present in its territory and it does not extradite the person.', ch: 'Chapter III - Procedural measures', part: null, kw: 'jurisdiction,territorial,nationality,extradite or prosecute' },
        // Chapter IV — International cooperation
        { num: 'Article 29', title: 'General provisions on international cooperation', content: 'States Parties shall cooperate with one another in conformity with this Convention and applicable international instruments and arrangements. States Parties shall, as appropriate and consistent with their domestic legal system, enhance channels of communication between their competent authorities, agencies and services.', ch: 'Chapter IV - International cooperation', part: null, kw: 'international cooperation,communication channels,mutual assistance' },
        { num: 'Article 30', title: 'Extradition', content: 'The offences established in this Convention shall be deemed to be included as extraditable offences in any extradition treaty existing between States Parties. States Parties undertake to include such offences as extraditable offences in every extradition treaty to be concluded between them. If a State Party that makes extradition conditional on the existence of a treaty receives a request for extradition from another State Party with which it has no extradition treaty, it may consider this Convention as the legal basis for extradition in respect of offences established herein.', ch: 'Chapter IV - International cooperation', part: null, kw: 'extradition,treaty basis,dual criminality' },
        { num: 'Article 31', title: 'Mutual legal assistance', content: 'States Parties shall afford one another the widest measure of mutual legal assistance in investigations, prosecutions and judicial proceedings in relation to the offences established in this Convention and the collection, preservation, production and sharing of electronic evidence in relation to any serious crime. Mutual legal assistance shall be afforded to the fullest extent possible under relevant laws, treaties, agreements and arrangements of the requested State Party.', ch: 'Chapter IV - International cooperation', part: null, kw: 'mutual legal assistance,MLA,electronic evidence' },
        { num: 'Article 32', title: 'Expedited preservation of stored electronic data', content: 'A State Party may request another State Party to order or otherwise obtain the expeditious preservation of data stored by means of an information and communications technology system located within the territory of that other State Party.', ch: 'Chapter IV - International cooperation', part: null, kw: 'cross-border preservation,expedited preservation' },
        { num: 'Article 33', title: 'Expedited disclosure of preserved traffic data', content: 'Where a State Party executing a preservation request discovers that a service provider in another State was involved in the transmission of the communication, the executing Party shall expeditiously disclose to the requesting Party a sufficient amount of traffic data to identify that service provider.', ch: 'Chapter IV - International cooperation', part: null, kw: 'traffic data disclosure,service provider identification' },
        { num: 'Article 34', title: 'Accessing stored electronic data', content: 'A State Party may request another State Party to search or similarly access, seize or similarly secure, and disclose electronic data stored by means of an information and communications technology system located within the territory of the requested State Party.', ch: 'Chapter IV - International cooperation', part: null, kw: 'cross-border access,stored data,search and seizure' },
        { num: 'Article 35', title: 'Real-time collection of traffic data', content: 'States Parties shall provide mutual assistance in the real-time collection of traffic data associated with specified communications in their territory transmitted by means of an information and communications technology system, subject to conditions and safeguards provided under domestic law.', ch: 'Chapter IV - International cooperation', part: null, kw: 'real-time collection,cross-border surveillance,traffic data' },
        { num: 'Article 36', title: 'Real-time interception of content data', content: 'States Parties shall provide mutual assistance in the real-time collection or recording of content data of specified communications transmitted by means of an information and communications technology system, to the extent permitted under their applicable treaties and domestic laws.', ch: 'Chapter IV - International cooperation', part: null, kw: 'content interception,cross-border interception' },
        { num: 'Article 37', title: '24/7 point of contact network', content: 'Each State Party shall designate a point of contact available on a 24/7 basis to ensure the provision of immediate assistance for investigations or proceedings concerning offences covered by this Convention and for the collection, preservation, and sharing of electronic evidence of any serious crime. Such assistance shall include facilitating or directly carrying out technical advice, preservation of data, collection of evidence, provision of legal information, and locating of suspects.', ch: 'Chapter IV - International cooperation', part: null, kw: '24/7 network,point of contact,immediate assistance' },
        { num: 'Article 38', title: 'Joint investigations', content: 'States Parties shall consider concluding bilateral or multilateral agreements or arrangements whereby the competent authorities concerned may establish joint investigative bodies. In the absence of such agreements, joint investigations may be undertaken on a case-by-case basis.', ch: 'Chapter IV - International cooperation', part: null, kw: 'joint investigations,bilateral agreements,cooperative investigation' },
        // Chapter V — Preventive measures
        { num: 'Article 39', title: 'Preventive measures', content: 'Each State Party shall adopt appropriate measures, including through legislation, to prevent cybercrime, taking into account the relevant elements of the use of best practices and the results of relevant research, including the promotion of cooperation with relevant private sector entities, the development of domestic and international standards and guidelines for security of information and communications technology systems, and education and awareness-raising activities.', ch: 'Chapter V - Preventive measures', part: null, kw: 'prevention,best practices,public-private cooperation,awareness' },
        // Chapter VI — Technical assistance and information exchange
        { num: 'Article 40', title: 'Technical assistance', content: 'States Parties shall, as appropriate, make concrete efforts to provide and strengthen technical assistance to developing countries in the implementation of this Convention through training, provision of equipment, expertise, and financial assistance. States Parties shall make efforts to contribute adequate and regular voluntary contributions to an account established for that purpose.', ch: 'Chapter VI - Technical assistance', part: null, kw: 'technical assistance,capacity building,developing countries,training' },
        // Chapter VII — Mechanisms
        { num: 'Article 41', title: 'Conference of the States Parties', content: 'A Conference of the States Parties to the Convention is hereby established to improve the capacity of and cooperation between States Parties to achieve the objectives set forth in this Convention and to promote and review its implementation.', ch: 'Chapter VII - Mechanisms', part: null, kw: 'conference of parties,review mechanism,implementation' },
        // Additional key articles
        { num: 'Article 42', title: 'Secretariat', content: 'The Secretary-General of the United Nations shall provide the necessary secretariat services to the Conference of the States Parties to the Convention.', ch: 'Chapter VII - Mechanisms', part: null, kw: 'secretariat,UN,administration' },
        // Chapter VIII — Final provisions (selected)
        { num: 'Article 50', title: 'Signature, ratification, and accession', content: 'This Convention shall be open for signature by all States and by regional economic integration organizations. The Convention shall be subject to ratification, acceptance or approval. It shall enter into force on the ninetieth day after the date of deposit of the fortieth instrument of ratification, acceptance, approval or accession.', ch: 'Chapter VIII - Final provisions', part: null, kw: 'signature,ratification,entry into force,forty ratifications' },
        { num: 'Article 52', title: 'Reservations', content: 'No reservations may be made to this Convention that are incompatible with the object and purpose of this Convention.', ch: 'Chapter VIII - Final provisions', part: null, kw: 'reservations,limitations' },
    ];
    const insertMany = db.transaction(() => {
        for (const art of articles) {
            insertArticle.run(srcId, art.num, art.title, art.content, art.ch, art.part, art.kw);
        }
    });
    insertMany();
    console.log(`    UN Cybercrime Convention: ${articles.length} articles`);
}
